// // This module compares two 4-bit inputs and outputs a 2-bit signal indicating the result of the comparison: 00 when the inputs are not equal, 01 when in0 is less than in1, and 10 when in0 is greater than or equal to in1.
module top_module(
    input [3:0] in0,
    input [3:0] in1,
    output reg [1:0] out
);always @* begin
        if (in0 == in1) begin
            out = 2'b00;
        end else if (in0 > in1) begin
            out = 2'b01;
        end else begin
            out = 2'b10;
        end
    end

endmodule
